mapper.select:
SELECT COUNT(1) FROM biz_approval_project p WHERE COALESCE(p.del_flag, '0') = '0' AND p.process_status = '1'
AND p.park_id = #{parkId}
AND FIND_IN_SET(#{currentUser}, REPLACE(COALESCE(p.current_node, ''), ' ', '')) > 0

SELECT COUNT(1) FROM biz_approval_project p WHERE COALESCE(p.del_flag, '0') = '0' AND p.process_status = '1' AND COALESCE(p.update_time, p.applicant_time, p.create_time) < DATE_SUB(NOW(), INTERVAL 12 HOUR)
AND p.park_id = #{parkId}
AND FIND_IN_SET(#{currentUser}, REPLACE(COALESCE(p.current_node, ''), ' ', '')) > 0

SELECT COUNT(1) FROM biz_service_workorder w WHERE COALESCE(w.del_flag, '0') = '0' AND w.order_status = '0'
AND w.park_id = #{parkId}
AND (w.create_by = #{currentUser} OR w.assign_to = #{currentUser})

SELECT c.customer_id AS customerId, c.enterprise_name AS enterpriseName, c.industry, LEFT(c.enterprise_name, 1) AS shortName FROM biz_customer c WHERE c.del_flag = '0' AND c.status = '0'
AND c.park_id = #{parkId}
ORDER BY c.create_time DESC, c.customer_id DESC LIMIT 12
